def render(self, context: Dict[str, Any]) -> str:
    def replace(match):
        name = match.group(1)
        default = match.group(3)
        if name in context:
            return str(context[name])
        if default is not None:
            return default
        raise KeyError(f"Missing template variable: {name}")
    return VARIABLE_RE.sub(replace, self.source)
